  "get_system_overview": {
    "description": "Retrieves the current simulation time, a list of active disruptions (including location, severity, and estimated clearance time), and the total count of available standby units in the depot.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "current_sim_time": "08:00:00",
      "standby_units_available": 5,
      "disruptions": [
        {
          "id": "INC-21B",
          "location": "S21-B",
          "severity": "Critical",
          "estimated_clearance_time": "08:45:00",
          "impacted_route": "Blue-Line-Local"
        }
      ]
    }
  },
  "get_corridor_metrics": {
    "description": "Returns current performance data (HDF and TDI) for a specific range of stops.",
    "parameters": {
      "type": "object",
      "properties": {
        "corridor_name": {
          "type": "string",
          "description": "Identifier for the corridor (e.g., 'South' or 'North')."
        },
        "start_stop": {
          "type": "string",
          "description": "Starting stop ID."
        },
        "end_stop": {
          "type": "string",
          "description": "Ending stop ID."
        }
      },
      "required": [
        "corridor_name",
        "start_stop",
        "end_stop"
      ]
    },
    "example_output": {
      "hdf": 1.95,
      "tdi": 0.9
    }
  },
  "list_vehicles_on_route": {
    "description": "Retrieves real-time status for all vehicles on a specific route, including current stop, passenger load, and position relative to any blockages.",
    "parameters": {
      "type": "object",
      "properties": {
        "route_name": {
          "type": "string",
          "description": "e.g., 'Blue-Line-Local'."
        }
      },
      "required": [
        "route_name"
      ]
    },
    "example_output": {
      "vehicles": [
        {
          "v_id": "BLL-101",
          "current_stop": "S19",
          "passengers": 85,
          "is_ahead_of_blockage": false
        }
      ]
    }
  },
  "dispatch_standby_unit": {
    "description": "Dispatches a single standby unit from the depot to enter service at a specific stop.",
    "parameters": {
      "type": "object",
      "properties": {
        "route_name": {
          "type": "string"
        },
        "insertion_stop": {
          "type": "string",
          "description": "Stop ID where the vehicle begins its route."
        }
      },
      "required": [
        "route_name",
        "insertion_stop"
      ]
    },
    "example_output": {
      "unit_id": "STBY-09",
      "status": "Dispatched"
    }
  },
  "apply_vehicle_intervention": {
    "description": "Executes a recovery command on a specific vehicle. Note: Commands fail if Route Crowding Ratio (RCR) is >= 0.80.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string"
        },
        "action": {
          "type": "string",
          "enum": [
            "Express_Drop_Off_Only",
            "Short_Turn",
            "Resume_Normal"
          ]
        },
        "turn_at_stop": {
          "type": "string",
          "description": "Required for Short_Turn; the stop where the vehicle will reverse."
        }
      },
      "required": [
        "vehicle_id",
        "action"
      ]
    },
    "example_output": {
      "success": true,
      "observed_rcr": 0.45
    }
  },
  "advance_sim_time": {
    "description": "Advances the simulation clock by a specific number of minutes to allow interventions to process.",
    "parameters": {
      "type": "object",
      "properties": {
        "minutes": {
          "type": "integer"
        }
      },
      "required": [
        "minutes"
      ]
    },
    "example_output": {
      "new_sim_time": "08:15:00"
    }
  },
